var treesVoxelDrawingDatasByHeight = [
    tree13,
    tree15,
    tree17,
    tree25,
    tree29,
    tree36,
    tree39,
    tree40,
]

export function getTreeVoxelDrawingDataByHeight(h: number): IVoxelDrawingDataSerialized {
    let bestMatch = treesVoxelDrawingDatasByHeight[0];
    let bestMatchDiff = Math.abs(h - bestMatch.hK);

    for (let i = 1; i < treesVoxelDrawingDatasByHeight.length; i++) {
        const treeData = treesVoxelDrawingDatasByHeight[i];
        const diff = Math.abs(h - treeData.hK);
        if (diff < bestMatchDiff) {
            bestMatch = treeData;
            bestMatchDiff = diff;
        }
    }

    return bestMatch;
}